def ok(label, condition, detail=""):
    status = "通过" if condition else "失败"
    suffix = f" - {detail}" if detail else ""
    print(f"[{status}] {label}{suffix}")
    return condition


def sha256(path):
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def csv_int(row, field):
    try:
        return int(str(row.get(field, "") or "0").strip())
    except ValueError:
        return 0


def as_int(value):
    try:
        return int(str(value).strip())
    except (TypeError, ValueError):
        return None


def stable_id(prefix, parts):
    text = "|".join(str(part) for part in parts)
    return f"{prefix}-{hashlib.sha1(text.encode('utf-8')).hexdigest()[:16]}"


def stable_id_sha256(prefix, parts):
    text = "|".join(str(part) for part in parts)
    return f"{prefix}-{hashlib.sha256(text.encode('utf-8')).hexdigest()[:16]}"


def counter_text(counter):
    return "；".join(f"{key}:{value}" for key, value in sorted(counter.items())) if counter else ""


def join_unique(rows, field):
    values = []
    seen = set()
    for row in rows:
        value = row.get(field, "")
        if value and value not in seen:
            seen.add(value)
            values.append(value)
    return "；".join(values)


def sha_list(values):
    normalized = "；".join(sorted({value for value in values if value}))
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()


def sha256_values(values):
    normalized = sorted({str(value).strip() for value in values if str(value).strip()})
    if not normalized:
        return ""
    return hashlib.sha256("\n".join(normalized).encode("utf-8")).hexdigest()


def count_value(rows, field, value):
    return sum(row.get(field, "") == value for row in rows)


def unique_value_count(rows, field):
    return len({row.get(field, "") for row in rows if row.get(field, "")})


def page_side_key(row):
    return (str(row.get("来源页码", "")).strip(), str(row.get("版面列", "")).strip())


def group_by_page_side(rows):
    grouped = defaultdict(list)
    for row in rows:
        grouped[page_side_key(row)].append(row)
    return grouped


def group_by_major_page_side(rows, major_to_page_side):
    grouped = defaultdict(list)
    for row in rows:
        key = major_to_page_side.get(row.get("专业行ID", ""))
        if key:
            grouped[key].append(row)
    return grouped


def script_list_constant(path, name):
    tree = ast.parse(path.read_text(encoding="utf-8"))
    for node in tree.body:
        if not isinstance(node, ast.Assign):
            continue
        if any(isinstance(target, ast.Name) and target.id == name for target in node.targets):
            return ast.literal_eval(node.value)
    raise ValueError(f"{name} not found in {path}")


def script_runtime_constant(path, name):
    namespace = runpy.run_path(str(path), run_name=f"__verify_{path.stem}")
    return namespace[name]


