        relation = row.get("机器候选与高校辅证关系", "")
        action = row.get("P0闭环动作桶", "")
        if relation == "R5-机器候选与高校辅证字段冲突":
            return priority == "S1-多源字段冲突优先核页"
        if semantic_status.startswith("M4-"):
            return priority == "S2-机器候选语义异常优先排除"
